codeExamples.code:
/* Block element: takes full width */
div {
  width: 300px;
  height: 100px;
  background-color: lightblue;
}

/* Inline element: width and height are IGNORED */
span {
  width: 300px;  /* has no effect */
  height: 100px; /* has no effect */
  background-color: lightyellow;
}

/* Inline-block: respects width/height like block,
   but stays in the inline flow */
.badge {
  display: inline-block;
  width: 80px;
  height: 30px;
  background-color: lightgreen;
}

.card {
  width: 350px;
  height: 200px;
  background-color: #f5f5f5;
}

/* Min and max constraints */
.flexible-card {
  width: 50%;
  min-width: 200px;
  max-width: 600px;
  min-height: 100px;
  background-color: #e0e0e0;
}

/* Full viewport height */
.hero {
  width: 100%;
  height: 100vh;
  background-color: #333;
}

/* When content exceeds the box size */
.small-box {
  width: 200px;
  height: 100px;
  background-color: #ffeeba;

  /* Default: content overflows visibly */
  overflow: visible;
}

.scroll-box {
  width: 200px;
  height: 100px;
  background-color: #d4edda;

  /* Add scrollbar when content overflows */
  overflow: auto;
}

.hidden-box {
  width: 200px;
  height: 100px;
  background-color: #f8d7da;

  /* Clip overflowing content */
  overflow: hidden;
}

/* Force inline elements to be block */
span.block {
  display: block;
  width: 200px;
  height: 50px;
  background-color: coral;
}

/* Force block elements to be inline */
div.inline {
  display: inline;
  /* width and height will be ignored now */
}

/* Inline-block: best of both worlds */
.nav-item {
  display: inline-block;
  width: 120px;
  height: 40px;
  text-align: center;
  line-height: 40px;
  background-color: #007bff;
  color: white;
}

/* Remove from layout entirely */
.hidden {
  display: none;
}

